css:
/* 底栏QR按键隐藏 */#send_form:hover #qr--bar {    height: 40px;    transition: all 0.5s ease;}#qr--bar {    height: 0.1px;}

code span.comment {
    color: #999;
    font-style: italic;
}
body {
    font-family: 'ZhuqueFangsong', serif;
    line-height: 1.5;
    font-weight: 400; /* 调整字体粗细为400 */
}
@font-face {
    font-family: 'ZhuqueFangsong';
    src: url("http://sharkpan.xyz/f/qNLi3/ZhuqueFangsong.ttf") format('truetype');
    font-weight: 400; /* 设置字体粗细为400 */
    font-style: normal;
}


/* 高亮样式 */
code span.keyword {
    color: #007BFF; /* 关键字颜色 */
    font-weight: bold;
}

code span.string {
    color: #d14;
}

*{--black30a: rgb(255 255 255 / 30%);
--black50a: rgb(255 255 255 / 50%);
--black70a: rgb(255 255 255 / %);
--white20a: rgb(255 255 255 / 20%);
--white30a: rgb(255 255 255 / 30%);
--white50a: rgb(255 255 255 / 50%);
--grey30: rgb(255 255 255);
--grey30a: rgb(255 255 255 / 30%);
--grey7070a: rgb(255 255 255 / 70%);}

/* 添加占位符的样式 */
textarea::placeholder, input[type="text"]::placeholder {
    font-family: 'ZhuqueFangsong', serif;
    color: #999; /* 灰色占位符 */
    font-weight: 300; /* 更细的占位符字体 */
    font-size: 14px; /* 占位符稍小 */
}

/* 聚焦时样式 */
textarea:focus, input[type="text"]:focus {
    border-color: #000; /* 聚焦时边框保持黑色 */
    background-color: #f7f7f7; /* 微微变浅的灰白色背景 */
    box-shadow: 2px 2px 10px rgba(0, 0, 0, 0.5); /* 更深的阴影效果 */
}
textarea, input[type="text"] {
    font-family: 'ZhuqueFangsong', serif; /* 嵌入字体 */
    font-size: 16px; /* 字体大小 */
    font-weight:300; /* 字体粗细 */
    line-height: 1.6; /* 行高 */
    color: #000; /* 黑色字体 */
    background-color: #fff; /* 白色背景 */
    border: 1px solid #000; /* 黑色边框 */
    border-radius: 5px; /* 圆角 */
    padding: 10px; /* 内边距 */
    box-shadow: 3px 3px 5px rgba(0, 0, 0, 0.2); /* 黑色微弱阴影 */
    outline: none; /* 去掉默认聚焦时的外边框 */
    transition: all 0.3s ease; /* 动态效果 */
}

pre {
    background-color: #f8f9fa; /* 浅灰色背景 */
    color: #333; /* 深灰色字体 */
    border: 1px solid #e0e0e0; /* 浅灰色边框 */
    border-radius: 4px; /* 圆角 */
    padding: 8px; /* 内边距 */
    font-family: 'Courier New', monospace; /* 等宽字体 */
    font-size: 14px; /* 字体大小 */
    overflow: auto; /* 长内容滚动 */
}
code {
    background-color: #f0f0f0; /* 灰色背景 */
    color: #A690C6; /* 黑色文字 */
    font-family: inherit; /* 使用全局字体 */
    border: 1px solid #87CEEB; /* 浅蓝色边框 */

}

/* 父容器 */
.parent-container {
    background-color: transparent !important; /* 父级背景透明 */
}

/* 代码块样式 */
pre {
    position: relative; /* 确保可以定位子元素 */
    background-color: #FBF7FF !important; /* 浅蓝色背景 */
    color: #A690C6 !important; /* 黑色文字 */
   border: none !important; /* 去掉边框 */
    box-shadow: none !important; /* 去掉阴影 */
    padding: 12px; /* 内边距 */
    margin: 10px 0; /* 上下间距 */
    overflow: hidden; /* 防止内容溢出 */
}
/* 父容器 */
.parent-container {
    background-color: transparent !important; /* 父级背景透明 */
}

/* 代码块样式 */
pre {
    position: relative; /* 确保可以定位子元素 */
    background-color: #FBF7FF !important; /* 浅蓝色背景 */
    color: #A690C6 !important; /* 黑色文字 */
    border: none !important; /* 去掉边框 */
    box-shadow: none !important; /* 去掉阴影 */
    padding: 12px; /* 内边距 */
    margin: 10px 0; /* 上下间距 */
    overflow: hidden; /* 防止内容溢出 */
}

/* 子代码块 */
pre code {
    background-color: inherit !important; /* 继承父级背景色 */
    color: inherit !important; /* 继承文字颜色 */
    font-family: inherit; /* 全局字体 */
}


@font-face {
    font-family: 'ZhuqueFangsong';
    src: url("http://sharkpan.xyz/f/qNLi3/ZhuqueFangsong.ttf") format('truetype');
    font-weight: 400;
    font-style: normal;
}

/* 输入框背景装饰 */
textarea, input[type="text"] {
    background-image: 
        url('https://files.catbox.moe/r4vlzk.png?v=1'), /* 新的花朵图片 */
        url('https://files.catbox.moe/sc0tzo.png?v=1') !important;
    background-size: 
        35px auto,  
        40px auto !important;
    background-position: 
        left 2px top 3px,  
        left 40px top 3px !important; 
    background-repeat: 
        no-repeat !important;
    background-blend-mode: normal;
    opacity: 0.8 !important; /* 提高透明度，使输入框更透 */
    position: relative;
    isolation: isolate;
    padding-left: 90px;
    color: #361274 !important; /* 修改字体颜色为深紫色 */
}

/* 文字层置顶，确保输入清晰可见 */
textarea::placeholder, 
input[type="text"]::placeholder, 
textarea > *, 
input[type="text"] > * {
    position: relative !important;
    z-index: 10000 !important;
    mix-blend-mode: normal !important;
    text-shadow: 0 0 4px rgba(255, 255, 255, 0.8);
    color: #361274 !important; /* 修改占位符文字颜色为深紫色 */
}

.chat-message, .mes {
    position: relative;
    overflow: visible !important;
}

@keyframes float {
    0% { transform: translateY(0); }
    50% { transform: translateY(-12px); }
    100% { transform: translateY(0); }
}

.chat-message.user::after, 
.mes[is_user="true"]::after {
    content: "";
    display: block;
    width: 55px;
    height: 55px;
    background: url('https://files.catbox.moe/a9i54f.png') no-repeat center;
    background-size: contain;
    position: absolute;
    bottom: 5px;
    right: 5px; /* Slightly moved LinaBell right */
    opacity: 0.8;
    pointer-events: none;
    animation: float 2.5s infinite ease-in-out;
}

.chat-message.bot::after, 
.mes:not([is_user="true"])::after {
    content: "";
    display: block;
    width: 75px;
    height: 75px;
    background: url('https://files.catbox.moe/t8et0l.png') no-repeat center;
    background-size: contain;
    position: absolute;
    bottom: 5px;
    left: -10px; /* Moved StellaLou further left */
    opacity: 0.7;
    pointer-events: none;
    animation: float 2.5s infinite ease-in-out;
}

.chat-message.user, .mes[is_user="true"] {
    background-color: rgba(255, 245, 250, 0.9) !important;
}

.chat-message.bot, .mes:not([is_user="true"]) {
    background-color: rgba(250, 245, 255, 0.9) !important;
}
